def sort_list(data: list[int]) -> list[int]:
    import numpy as np
    # Use view-based sorting with pre-allocated output
    arr = np.asarray(data, dtype=np.int32)
    sorted_arr = np.sort(arr, kind='quicksort')
    return sorted_arr.tolist()

def sort_list(data: list[int]) -> list[int]:
    import numpy as np
    # Use int64 to potentially leverage better SIMD optimization on ARM
    arr = np.fromiter(data, dtype=np.int64, count=len(data))
    arr.sort(kind='quicksort')
    return arr.tolist()

def sort_list(data: list[int]) -> list[int]:
    import numpy as np
    # Try mergesort which might be faster on ARM for this data size
    arr = np.fromiter(data, dtype=np.int32, count=len(data))
    arr.sort(kind='mergesort')
    return arr.tolist()
